/// <summary>
/// Represents a social media post for publishing.
/// </summary>
[Description("Represents a social media post for publishing.")]
public record Post
{
    [Key]
    [Description("Unique identifier for the post")]
    public string Id { get; init; } = string.Empty;

    [Description("Title or headline of the post")]
    public string Title { get; init; } = string.Empty;

    [Description("Main content/body of the post")]
    public string Text { get; init; } = string.Empty;

    [Description("URL for the post image or media")]
    public string? ImageLink { get; init; }

    [Description("Scheduled date and time for publishing")]
    public DateTime? PublishDate { get; init; }

    [Description("Reference to the Person who publishes this post")]
    public string? Author { get; init; }

    [Description("List of platforms to publish on (LinkedIn, X, Instagram)")]
    public List<string> Platforms { get; init; } = new();

    [Description("Current publication status")]
    public PostStatus Status { get; init; } = PostStatus.Draft;
}

[Description("Publication status of a social media post")]
public enum PostStatus
{
    [Description("Post is being drafted")]
    Draft,
    [Description("Post is scheduled for future publication")]
    Scheduled,
    [Description("Post has been published")]
    Published,
    [Description("Post has been archived")]
    Archived
}
